import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourList = ({ tours, setTours, setEditingTour }) => {
  const { user } = useAuth();

  const handleDelete = async (tourId) => {
    if (!window.confirm("Are you sure you want to delete this tour package?")) return;

    try {
      // 確保路徑改為 /api/tours
      await axiosInstance.delete(`/api/tours/${tourId}`, {
        headers: { Authorization: `Bearer ${user.token}` },
      });
      // 過濾掉刪除的項目，讓畫面立刻更新
      setTours(tours.filter((tour) => tour._id !== tourId));
    } catch (error) {
      alert('Failed to delete tour.');
    }
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      {tours.length === 0 ? (
        <p className="text-gray-500 italic">No tour packages found. Add one above!</p>
      ) : (
        tours.map((tour) => (
          <div key={tour._id} className="bg-white p-5 border-l-8 border-blue-600 rounded-lg shadow-md hover:shadow-lg transition-shadow">
            <div className="flex justify-between items-start">
              <h2 className="text-xl font-bold text-blue-800">{tour.title}</h2>
              {/* 價格標籤：這是旅遊系統的靈魂 */}
              <span className="bg-green-100 text-green-800 px-3 py-1 rounded-full font-bold">
                ${tour.price}
              </span>
            </div>

            <p className="text-gray-600 mt-2 line-clamp-2">{tour.description}</p>

            <div className="flex items-center mt-4 text-sm text-gray-500">
              <span className="mr-4">⏱ Duration: {tour.duration || 'N/A'}</span>
              <span>📍 Location: {tour.location || 'Australia'}</span>
            </div>

            <div className="mt-4 flex space-x-2">
              <button
                onClick={() => setEditingTour(tour)}
                className="flex-1 bg-yellow-500 hover:bg-yellow-600 text-white font-semibold py-2 px-4 rounded transition duration-200"
              >
                Edit Details
              </button>
              <button
                onClick={() => handleDelete(tour._id)}
                className="flex-1 bg-red-500 hover:bg-red-600 text-white font-semibold py-2 px-4 rounded transition duration-200"
              >
                Delete Package
              </button>
            </div>
          </div>
        ))
      )}
    </div>
  );
};

export default TourList;
